patch:
diff --git a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
index ed93b4491c50..142403843e1f 100644
--- a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
+++ b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
@@ -615,6 +615,20 @@ void DeadArgumentEliminationPass::surveyFunction(const Function &F) {
                       << " has musttail callers\n");
   }

+  if (HasMustTailCallers || HasMustTailCalls) {
+    LLVM_DEBUG(dbgs() << "DeadArgumentEliminationPass - " << F.getName()
+                      << " has musttail callers or calls, marking all return values as live\n");
+    RetValLiveness.assign(RetCount, Live);
+  }
+
+  if (HasMustTailCallers || HasMustTailCalls) {
+    LLVM_DEBUG(dbgs() << "DeadArgumentEliminationPass - " << F.getName()
+                      << " has musttail callers or calls, marking function as live\n");
+    markLive(F);
+    return;
+  }
+
+
   // Now we've inspected all callers, record the liveness of our return values.
   for (unsigned Ri = 0; Ri != RetCount; ++Ri)
     markValue(createRet(&F, Ri), RetValLiveness[Ri], MaybeLiveRetUses[Ri]);

